/** Lookup map: CUIPO fuente code → consolidated fuente code */
const consolidadaByCuipo = new Map(
  FUENTES_HOMOLOGADAS.map((f) => [f.cuipoCodigo, f.consolidadaCodigo])
);

/**
 * Returns the consolidated fuente code for a CUIPO fuente code.
 * RF and RB fuentes map to their parent vigencia fuente.
 * Returns null if the code is not found.
 */
export function getConsolidada(codigoCuipo: string): string | null {
  return consolidadaByCuipo.get(codigoCuipo.trim()) ?? null;
}
